import React, {useState} from "react";
import CardsCities from "./CardsCities";
import Box from '@mui/material/Box';
import TextField from '@mui/material/TextField';
import { useEffect } from "react";
import "../styles/searchCities.css"

import { useDispatch, useSelector } from "react-redux";
import citiesActions from "../redux/citiesActions";


export default function SearchCities() {
    const [inputValue, setInputValue] = useState("")
    // const [cities, setCities] = useState([])

    const dispatch = useDispatch()

    useEffect(() => {
        dispatch(citiesActions.filterCity())
        // axios.get("http://localhost:4000/api/cities")
        // .then(response => setCities(response.data.response.cities))
    }, [])

    const citiesRedux = useSelector(store => store.citiesReducer.city)

    // let city = citiesRedux.filter(city => city.cityname.toLowerCase().startsWith(inputValue.toLocaleLowerCase().trim()));

    return (
    <div className="body-cities">
        <div>
            <Box
                component="form"
                sx={{
                '& > :not(style)': { m: 1, width: '25ch' },
                }}
                noValidate
                autoComplete="off"
            >
                <TextField id="outlined-basic" label="Search cities!" variant="outlined" type={"text"} onKeyUp={(evento) => { setInputValue(evento.target.value) }} />
            </Box>
        </div>
        <div>
            <CardsCities input={inputValue} cities={citiesRedux}/>
            {/* {city.length > 0 ? (<CardsCities cardFilter={citiesRedux} />) : <p className="error">NOT FOUND!</p>} */}
        </div>
    </div>
    );
}
